CREATE TABLE digitaltwinapp.currencies (
    id             INTEGER      NOT NULL,
    code           VARCHAR(10)  NOT NULL,
    name           VARCHAR(100) NOT NULL,
    decimal_places SMALLINT     NOT NULL,
    CONSTRAINT currencies_pkey         PRIMARY KEY (id),
    CONSTRAINT currencies_code_unique  UNIQUE (code)
);

CREATE SEQUENCE digitaltwinapp.currencies_id_seq START WITH 105 INCREMENT BY 1;
ALTER TABLE digitaltwinapp.currencies ALTER COLUMN id SET DEFAULT nextval('digitaltwinapp.currencies_id_seq');

